        .downstream_dispatch_target
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let active_target = receipt
        .downstream_dispatch_active_target
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    matches!((ready_target, active_target), (Some(ready), Some(active)) if ready != active)
}

